<?php
/**
 * Sathi mascots — bundled as base64 data URIs so they are git-safe, self-contained,
 * and need no external hosting. Used for the chat avatar/launcher and the admin picker.
 *
 * @package RaiLabs\Sathi\Support
 */

namespace RaiLabs\Sathi\Support;

class Mascots {

    /** @return array<string,string> id => data URI */
    public static function all(): array {
        return [
        'mascot-1' => 'data:image/png;base64,',
        'mascot-2' => 'data:image/png;base64,',
        'mascot-3' => 'data:image/png;base64,',
        'mascot-4' => 'data:image/png;base64,',
        'mascot-5' => 'data:image/png;base64,',
        ];
    }

    public static function get( string $id ): string {
        $all = self::all();
        return $all[ $id ] ?? '';
    }

    /** @return array<string,string> id => human label */
    public static function labels(): array {
        return [
            'mascot-1' => 'Companion',
            'mascot-2' => 'Flat',
            'mascot-3' => 'Robot',
            'mascot-4' => 'Orb',
            'mascot-5' => 'Sticker',
        ];
    }
}
